import { readFileSync, writeFileSync, appendFileSync, existsSync, mkdirSync } from "node:fs";
import { dirname } from "node:path";
import { generateReadme } from "./generate.js";
export async function run(env) {
    const docPath = required(env.inputs, "doc_path");
    const outputPath = env.inputs.output_path?.trim() || "";
    const commentOnPr = env.inputs.comment_on_pr ?? "auto";
    const hideBadges = (env.inputs.hide_badges ?? "false").toLowerCase() === "true";
    const anchorPrefix = env.inputs.anchor_prefix?.trim() || "section-";
    const token = env.inputs.github_token ?? "";
    const read = env.readFile ?? ((p) => readFileSync(p, "utf8"));
    const exists = env.exists ?? ((p) => existsSync(p));
    const writeOutFile = env.writeFile ?? ((p, c) => {
        mkdirSync(dirname(p), { recursive: true });
        writeFileSync(p, c, "utf8");
    });
    const write = env.write ?? ((line) => process.stdout.write(`${line}\n`));
    if (!exists(docPath)) {
        write(`::error::doc-path "${docPath}" does not exist on disk.`);
        return { exitCode: 1, markdown: "", outputWritten: false, commentPosted: false, reason: "doc-path not found" };
    }
    let doc;
    try {
        doc = JSON.parse(read(docPath));
    }
    catch (e) {
        write(`::error::could not parse ProvenanceDoc at "${docPath}" — ${e.message}`);
        return { exitCode: 1, markdown: "", outputWritten: false, commentPosted: false, reason: "malformed ProvenanceDoc JSON" };
    }
    const markdown = generateReadme(doc, { hideBadges, anchorPrefix });
    setOutput(env, "markdown-length", String(markdown.length));
    let outputWritten = false;
    if (outputPath) {
        try {
            writeOutFile(outputPath, markdown);
            outputWritten = true;
            write(`::notice::Wrote ${markdown.length} chars of rendered Markdown to "${outputPath}".`);
        }
        catch (e) {
            write(`::error::could not write output-path "${outputPath}" — ${e.message}`);
            return { exitCode: 1, markdown, outputWritten: false, commentPosted: false, reason: "write failed" };
        }
    }
    setOutput(env, "output-written", String(outputWritten));
    write(`\n${markdown}\n`);
    const isPullRequest = env.GITHUB_EVENT_NAME === "pull_request";
    const wantsComment = commentOnPr === "true" || (commentOnPr === "auto" && isPullRequest);
    let commentPosted = false;
    let reason;
    if (wantsComment) {
        if (!token) {
            reason = "no github-token provided";
        }
        else if (!env.GITHUB_EVENT_PATH) {
            reason = "no GITHUB_EVENT_PATH";
        }
        else if (!env.GITHUB_REPOSITORY) {
            reason = "no GITHUB_REPOSITORY";
        }
        else {
            const event = JSON.parse(read(env.GITHUB_EVENT_PATH));
            const issueNumber = event.number ?? event.pull_request?.number;
            if (!issueNumber) {
                reason = "no PR number in event payload";
            }
            else {
                const body = `### Prompt Provenance README — \`${docPath}\`\n\n${markdown}\n\n_Generated by [prompt-provenance-readme-generator-action](https://github.com/mizcausevic-dev/prompt-provenance-readme-generator-action)._`;
                const poster = env.postComment ?? defaultPostComment;
                await poster({ token, repo: env.GITHUB_REPOSITORY, issueNumber, body });
                commentPosted = true;
            }
        }
    }
    return { exitCode: 0, markdown, outputWritten, commentPosted, reason };
}
function required(inputs, name) {
    const v = inputs[name];
    if (!v || v.length === 0)
        throw new Error(`input "${name}" is required`);
    return v;
}
function setOutput(env, key, value) {
    if (env.GITHUB_OUTPUT)
        appendFileSync(env.GITHUB_OUTPUT, `${key}=${value}\n`);
}
async function defaultPostComment(args) {
    const r = await fetch(`https://api.github.com/repos/${args.repo}/issues/${args.issueNumber}/comments`, {
        method: "POST",
        headers: {
            Accept: "application/vnd.github+json",
            Authorization: `Bearer ${args.token}`,
            "X-GitHub-Api-Version": "2022-11-28"
        },
        body: JSON.stringify({ body: args.body })
    });
    if (!r.ok)
        throw new Error(`GitHub API comment failed: ${r.status} ${await r.text()}`);
}
